1	use gloo::timers::callback::Timeout;
2	use web_sys::{Element, HtmlInputElement, HtmlSelectElement, HtmlTextAreaElement, KeyboardEvent};
3	use yew::prelude::*;
4	
5	pub mod config;
6	pub mod demos;
7	pub mod hardware;
8	pub mod runner;
9	
10	use demos::{DEMOS, default_demo_index};
11	use hardware::HardwarePanel;
12	use runner::Session;
13	
14	/// Per-tick instruction budget for the run loop. The `Session` runs at
15	/// most this many cor24 instructions per tick before yielding to the
16	/// browser. OCaml interpretation is heavier than BASIC, so this is
17	/// larger than the BASIC project's setting.
18	const DEFAULT_MAX_INSTRS: u64 = 500_000_000;
19	const TICK_DELAY_MS: u32 = 0;
20	
21	fn now_ms() -> f64 {
22	    js_sys::Date::now()
23	}
24	
25	#[derive(Clone, Copy, PartialEq, Eq)]
26	pub enum HelpTab {
27	    UserGuide,
28	    LanguageReference,
29	}
30	
31	pub enum Msg {
32	    SelectDemo(usize),
33	    SourceChanged(String),
34	    Run,
35	    Tick,
36	    Stop,
37	    Reset,
38	    Clear,
39	    IncreaseBudget,
40	    KeyDown(KeyboardEvent),
41	    InputChanged(String),
42	    InputSubmit,
43	    HistoryPrev,
44	    HistoryNext,
45	    ToggleS2,
46	    OpenHelp,
47	    CloseHelp,
48	    SetHelpTab(HelpTab),
49	}
50	
51	pub struct App {
52	    selected: usize,
53	    source: String,
54	    output: String,
55	    status: String,
56	    error: bool,
57	    session: Option<Session>,
58	    running: bool,
59	    max_instrs: u64,
60	    started_at: f64,
61	    elapsed_ms: f64,
62	    budget_exhausted: bool,
63	    input_line: String,
64	    awaiting_input: bool,
65	    // Submitted REPL inputs in chronological order; `history_cursor`
66	    // indexes from the end (0 = most recent) while the user is
67	    // walking the history, and is `None` when editing a fresh line.
68	    input_history: Vec<String>,
69	    history_cursor: Option<usize>,
70	    output_len_at_feed: Option<usize>,
71	    output_ref: NodeRef,
72	    input_ref: NodeRef,
73	    s2_on: bool,
74	    led_on: bool,
75	    help_open: bool,
76	    help_tab: HelpTab,
77	}
78	
79	impl App {
80	    fn load_demo(&mut self, idx: usize) {
81	        if let Some(demo) = DEMOS.get(idx) {
82	            self.selected = idx;
83	            self.source = demo.source.to_string();
84	            self.output.clear();
85	            self.status = "idle".into();
86	            self.error = false;
87	            self.session = None;
88	            self.running = false;
89	            self.budget_exhausted = false;
90	            self.elapsed_ms = 0.0;
91	            self.input_line.clear();
92	            self.awaiting_input = false;
93	            self.input_history.clear();
94	            self.history_cursor = None;
95	        }
96	    }
97	
98	    fn start_run(&mut self, ctx: &Context<Self>) {
99	        let interactive = DEMOS
100	            .get(self.selected)
101	            .map(|d| d.interactive)
102	            .unwrap_or(false);
103	        self.session = Some(if interactive {
104	            Session::new_interactive(&self.source)
105	        } else {
106	            Session::new(&self.source)
107	        });
108	        self.input_line.clear();
109	        self.awaiting_input = false;
110	        self.input_history.clear();
111	        self.history_cursor = None;
112	        self.running = true;
113	        self.error = false;
114	        self.budget_exhausted = false;
115	        self.output.clear();
116	        self.started_at = now_ms();
117	        self.elapsed_ms = 0.0;
118	        self.status = "running...".into();
119	        self.schedule_tick(ctx);
120	    }
121	
122	    fn schedule_tick(&self, ctx: &Context<Self>) {
123	        let link = ctx.link().clone();
124	        Timeout::new(TICK_DELAY_MS, move || link.send_message(Msg::Tick)).forget();
125	    }
126	
127	    fn finish(&mut self, status: String, error: bool) {
128	        self.running = false;
129	        self.status = status;
130	        self.error = error;
131	        self.elapsed_ms = now_ms() - self.started_at;
132	        if let Some(s) = &self.session {
133	            self.output = s.clean_output();
134	        }
135	    }
136	}
137	
138	impl Component for App {
139	    type Message = Msg;
140	    type Properties = ();
141	
142	    fn create(_ctx: &Context<Self>) -> Self {
143	        let idx = default_demo_index();
144	        let demo = &DEMOS[idx];
145	        Self {
146	            selected: idx,
147	            source: demo.source.to_string(),
148	            output: String::new(),
149	            status: "idle".into(),
150	            error: false,
151	            session: None,
152	            running: false,
153	            max_instrs: DEFAULT_MAX_INSTRS,
154	            started_at: 0.0,
155	            elapsed_ms: 0.0,
156	            budget_exhausted: false,
157	            input_line: String::new(),
158	            awaiting_input: false,
159	            input_history: Vec::new(),
160	            history_cursor: None,
161	            output_len_at_feed: None,
162	            output_ref: NodeRef::default(),
163	            input_ref: NodeRef::default(),
164	            s2_on: false,
165	            led_on: false,
166	            help_open: false,
167	            help_tab: HelpTab::UserGuide,
168	        }
169	    }
170	
171	    fn rendered(&mut self, _ctx: &Context<Self>, _first_render: bool) {
172	        if let Some(el) = self.output_ref.cast::<Element>() {
173	            el.set_scroll_top(el.scroll_height());
174	        }
175	        if self.awaiting_input
176	            && let Some(el) = self.input_ref.cast::<HtmlInputElement>()
177	        {
178	            let _ = el.focus();
179	        }
180	    }
181	
182	    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
183	        match msg {
184	            Msg::SelectDemo(i) => {
185	                self.load_demo(i);
186	                self.max_instrs = DEFAULT_MAX_INSTRS;
187	                true
188	            }
189	            Msg::SourceChanged(v) => {
190	                self.source = v;
191	                false
192	            }
193	            Msg::Run => {
194	                self.max_instrs = DEFAULT_MAX_INSTRS;
195	                self.start_run(ctx);
196	                true
197	            }
198	            Msg::IncreaseBudget => {
199	                self.max_instrs = self.max_instrs.saturating_mul(4);
200	                self.start_run(ctx);
201	                true
202	            }
203	            Msg::Stop => {
204	                if self.running {
205	                    self.finish("stopped".into(), false);
206	                }
207	                true
208	            }
209	            Msg::Reset => {
210	                let idx = self.selected;
211	                self.running = false;
212	                self.session = None;
213	                self.load_demo(idx);
214	                self.max_instrs = DEFAULT_MAX_INSTRS;
215	                self.s2_on = false;
216	                self.led_on = false;
217	                true
218	            }
219	            Msg::ToggleS2 => {
220	                self.s2_on = !self.s2_on;
221	                if let Some(s) = self.session.as_mut() {
222	                    s.set_switch(self.s2_on);
223	                }
224	                true
225	            }
226	            Msg::Clear => {
227	                self.output.clear();
228	                if !self.running {
229	                    self.status = "idle".into();
230	                    self.error = false;
231	                    self.budget_exhausted = false;
232	                }
233	                true
234	            }
235	            Msg::Tick => {
236	                if !self.running {
237	                    return false;
238	                }
239	                let Some(session) = self.session.as_mut() else {
240	                    self.running = false;
241	                    return true;
242	                };
243	                let interactive = DEMOS
244	                    .get(self.selected)
245	                    .map(|d| d.interactive)
246	                    .unwrap_or(false);
247	                if !interactive {
248	                    let remaining = self.max_instrs.saturating_sub(session.instructions());
249	                    if remaining == 0 {
250	                        self.budget_exhausted = true;
251	                        let instrs = session.instructions();
252	                        self.finish(format!("halted (budget) -- {} instrs", instrs), true);
253	                        return true;
254	                    }
255	                }
256	                // Push the current S2 state into the cor24 switch
257	                // register before each batch so any `switch ()` reads
258	                // the demo issues this tick see fresh data.
259	                session.set_switch(self.s2_on);
260	                let result = session.tick();
261	                self.led_on = session.led_on();
262	                if session.is_awaiting_input() {
263	                    // is_awaiting_input fires as soon as our rx_queue
264	                    // empties, which can happen BEFORE the interpreter
265	                    // has finished evaluating the line we fed it. If
266	                    // output hasn't grown since the last feed_input,
267	                    // the interp is still mid-evaluation — keep ticking
268	                    // instead of stopping and forcing the user to hit
269	                    // Enter a second time.
270	                    let still_processing = self
271	                        .output_len_at_feed
272	                        .is_some_and(|len| session.clean_output().len() <= len);
273	                    if still_processing {
274	                        self.output = session.clean_output();
275	                        self.elapsed_ms = now_ms() - self.started_at;
276	                        self.status = format!(
277	                            "running... {} instrs, {:.0} ms",
278	                            session.instructions(),
279	                            self.elapsed_ms
280	                        );
281	                        self.schedule_tick(ctx);
282	                        return true;
283	                    }
284	                    self.output_len_at_feed = None;
285	                    self.awaiting_input = true;
286	                    self.output = session.clean_output();
287	                    self.elapsed_ms = now_ms() - self.started_at;
288	                    self.status = format!(
289	                        "awaiting input ({} instrs, {:.0} ms)",
290	                        session.instructions(),
291	                        self.elapsed_ms
292	                    );
293	                    return true;
294	                }
295	                if result.done {
296	                    let instrs = session.instructions();
297	                    let reason = session.stop_reason();
298	                    let halted = session.is_halted();
299	                    self.finish(
300	                        format!(
301	                            "{} ({} instrs, {:.0} ms)",
302	                            reason,
303	                            instrs,
304	                            now_ms() - self.started_at
305	                        ),
306	                        !halted,
307	                    );
308	                } else {
309	                    self.output = session.clean_output();
310	                    self.elapsed_ms = now_ms() - self.started_at;
311	                    self.status = format!(
312	                        "running... {} instrs, {:.0} ms",
313	                        session.instructions(),
314	                        self.elapsed_ms
315	                    );
316	                    self.schedule_tick(ctx);
317	                }
318	                true
319	            }
320	            Msg::InputChanged(v) => {
321	                self.input_line = v;
322	                // User is editing a fresh line; leave any history walk.
323	                self.history_cursor = None;
324	                false
325	            }
326	            Msg::InputSubmit => {
327	                if !self.awaiting_input {
328	                    return false;
329	                }
330	                let line = std::mem::take(&mut self.input_line);
331	                // Record non-empty submits; skip consecutive duplicates so
332	                // hitting Enter twice doesn't bloat the history.
333	                if !line.is_empty() && self.input_history.last() != Some(&line) {
334	                    self.input_history.push(line.clone());
335	                }
336	                self.history_cursor = None;
337	                if let Some(session) = self.session.as_mut() {
338	                    self.output_len_at_feed = Some(session.clean_output().len());
339	                    session.feed_input(&line);
340	                }
341	                self.awaiting_input = false;
342	                self.status = "running...".into();
343	                self.schedule_tick(ctx);
344	                true
345	            }
346	            Msg::HistoryPrev => {
347	                if self.input_history.is_empty() {
348	                    return false;
349	                }
350	                let next = match self.history_cursor {
351	                    None => 0,
352	                    Some(i) if i + 1 < self.input_history.len() => i + 1,
353	                    Some(i) => i,
354	                };
355	                self.history_cursor = Some(next);
356	                let idx = self.input_history.len() - 1 - next;
357	                self.input_line = self.input_history[idx].clone();
358	                true
359	            }
360	            Msg::HistoryNext => {
361	                let Some(cursor) = self.history_cursor else {
362	                    return false;
363	                };
364	                if cursor == 0 {
365	                    self.history_cursor = None;
366	                    self.input_line.clear();
367	                } else {
368	                    let next = cursor - 1;
369	                    self.history_cursor = Some(next);
370	                    let idx = self.input_history.len() - 1 - next;
371	                    self.input_line = self.input_history[idx].clone();
372	                }
373	                true
374	            }
375	            Msg::KeyDown(e) => {
376	                if e.key() == "Enter" && (e.ctrl_key() || e.meta_key()) {
377	                    e.prevent_default();
378	                    ctx.link().send_message(Msg::Run);
379	                } else if e.key() == "Escape" {
380	                    if self.help_open {
381	                        e.prevent_default();
382	                        ctx.link().send_message(Msg::CloseHelp);
383	                    } else if self.running {
384	                        e.prevent_default();
385	                        ctx.link().send_message(Msg::Stop);
386	                    }
387	                }
388	                false
389	            }
390	            Msg::OpenHelp => {
391	                self.help_open = true;
392	                true
393	            }
394	            Msg::CloseHelp => {
395	                self.help_open = false;
396	                true
397	            }
398	            Msg::SetHelpTab(tab) => {
399	                self.help_tab = tab;
400	                true
401	            }
402	        }
403	    }
