1	//! OCaml interpreter session for the browser.
2	//!
3	//! This is the same architecture used by `../web-sw-cor24-pascal`,
4	//! `../web-sw-cor24-snobol4`, and the rest of the family: load
5	//! `pvm.bin` (assembled from the canonical `asm/pvm.s`) at address 0
6	//! of a `cor24-emulator::EmulatorCore`, place the linked OCaml
7	//! interpreter image (`ocaml.p24m`) at `OCAML_LOAD_ADDR`, patch the
8	//! pvm `code_ptr` slot, and let pvm boot. pvm sees the `P24M` magic at
9	//! the load address and walks the multi-unit header itself, so we
10	//! avoid every multi-unit / IRT / opcode-table edge case the previous
11	//! Rust-native interpreter had to handle.
12	//!
13	//! The OCaml REPL on top of pvm reads its source from UART terminated
14	//! by `0x04` (EOT). One-shot sessions queue source + EOT at startup;
15	//! interactive sessions leave the stream open so `feed_input()` can
16	//! append more bytes as the user types.
17	
18	use std::collections::VecDeque;
19	
20	use cor24_emulator::{EmulatorCore, StopReason};
21	
22	use crate::config::{OCAML_LOAD_ADDR, OCAML_P24M, PVM_BIN, label_addr};
23	
24	/// Per-tick total instruction budget across all inner sub-batches.
25	/// Snobol4 and friends use ~200k as a single batch; OCaml is heavier
26	/// so we run a larger total budget broken into smaller inner batches
27	/// so we can feed UART bytes between them (see `INNER_BATCH`).
28	pub const DEFAULT_BATCH: u64 = 1_000_000;
29	
30	/// Inner sub-batch size between UART feeds. Small enough that the
31	/// next source byte is delivered before the interpreter spends much
32	/// time busy-polling the UART RX register; large enough to amortize
33	/// the per-call overhead of `EmulatorCore::run_batch`. Tuned by
34	/// inspection of the OCaml REPL's read loop -- a few hundred cor24
35	/// instructions consume a byte and resume polling.
36	const INNER_BATCH: u64 = 50_000;
37	
38	/// Memory-mapped UART status port. Bit 0 set means a byte is sitting
39	/// in the RX register waiting to be read; clear means the register
40	/// is empty and we can push a fresh byte without overflow.
41	const IO_UARTSTAT: u32 = 0xFF_0101;
42	const UARTSTAT_RX_READY: u8 = 0x01;
43	
44	pub struct Session {
45	    emu: EmulatorCore,
46	    pub instructions: u64,
47	    pub done: bool,
48	    pub halted: bool,
49	    pub stop_reason: String,
50	    interactive: bool,
51	    /// UART RX has FIFO depth 1; we drain at most one byte per tick.
52	    rx_queue: VecDeque<u8>,
53	    /// If true, every byte we drain is the program's source. Once
54	    /// drained, we set this to false and the queue becomes the channel
55	    /// for `feed_input`.
56	    seeding_source: bool,
57	}
58	
59	pub struct TickResult {
60	    pub done: bool,
61	}
62	
63	/// Remove REPL prompt segments from a raw UART transcript. Anywhere a
64	/// line starts with `"> "` (the OCaml REPL's prompt), drop the prompt
65	/// and the echoed source bytes that follow it up to and including the
66	/// next newline. Result text on subsequent lines passes through.
67	///
68	/// Handles both shapes:
69	/// - One-shot, no trailing newline:
70	///   `"> print_int 4242"` -> `"42"` (echo runs to end of buffer for
71	///   12 bytes then result begins; we anchor on the source we sent
72	///   only when echo ends at a newline, so the no-newline case still
73	///   conflates echo with result -- callers wanting clean separation
74	///   should ensure their source ends with `\n`).
75	/// - Multi-line REPL session: each `"> <line>\n"` is dropped.
76	fn strip_prompt_echoes(raw: &str) -> String {
77	    let mut out = String::with_capacity(raw.len());
78	    let bytes = raw.as_bytes();
79	    let mut i = 0;
80	    let mut at_line_start = true;
81	    while i < bytes.len() {
82	        if at_line_start && i + 1 < bytes.len() && bytes[i] == b'>' && bytes[i + 1] == b' ' {
83	            // Skip "> " then echoed source up to and including the next newline.
84	            i += 2;
85	            while i < bytes.len() {
86	                let b = bytes[i];
87	                i += 1;
88	                if b == b'\n' {
89	                    break;
90	                }
91	            }
92	            at_line_start = true;
93	            continue;
94	        }
95	        let b = bytes[i];
96	        out.push(b as char);
97	        at_line_start = b == b'\n';
98	        i += 1;
99	    }
100	    out
101	}
102	
103	impl Session {
104	    pub fn new(source: &str) -> Self {
105	        Self::new_with_mode(source, false)
106	    }
107	
108	    pub fn new_interactive(source: &str) -> Self {
109	        Self::new_with_mode(source, true)
110	    }
111	
112	    fn new_with_mode(source: &str, interactive: bool) -> Self {
113	        let mut emu = EmulatorCore::new();
114	        // Skip the UART TX busy-cycle simulation — we want bytes
115	        // through immediately rather than throttled at hardware speed.
116	        emu.set_uart_tx_busy_cycles(0);
117	
118	        // Place pvm.bin at address 0.
119	        for (i, &b) in PVM_BIN.iter().enumerate() {
120	            emu.write_byte(i as u32, b);
121	        }
122	
123	        // Place ocaml.p24m at the address its absolute data refs were
124	        // baked for (`p24-load --load-addr 0x010000`).
125	        for (i, &b) in OCAML_P24M.iter().enumerate() {
126	            emu.write_byte(OCAML_LOAD_ADDR + i as u32, b);
127	        }
128	
129	        // Patch pvm's `code_ptr` slot to point at the loaded p24m. At
130	        // boot, pvm reads code_ptr, sees the "P24M" magic, and runs
131	        // its `init_p24m` path which sets up code_base, unit_table,
132	        // irt_base, and entry_point from the header.
133	        let code_ptr_addr = label_addr("code_ptr");
134	        emu.write_byte(code_ptr_addr, OCAML_LOAD_ADDR as u8);
135	        emu.write_byte(code_ptr_addr + 1, (OCAML_LOAD_ADDR >> 8) as u8);
136	        emu.write_byte(code_ptr_addr + 2, (OCAML_LOAD_ADDR >> 16) as u8);
137	
138	        // Start at pvm's reset entry (address 0).
139	        emu.set_pc(0);
140	        emu.resume();
141	
142	        let mut rx_queue: VecDeque<u8> = source.bytes().collect();
143	        // Ensure each source ends with a newline so the REPL's read
144	        // loop terminates the echoed line cleanly. Without this, a
145	        // one-shot like `print_int 42` (no trailing newline) emits
146	        // `"> print_int 4242"` with no separator between echoed
147	        // source and the computed result, and clean_output() can't
148	        // tell them apart.
149	        if !source.ends_with('\n') {
150	            rx_queue.push_back(b'\n');
151	        }
152	        if !interactive {
153	            rx_queue.push_back(0x04);
154	        }
155	
156	        Self {
157	            emu,
158	            instructions: 0,
159	            done: false,
160	            halted: false,
161	            stop_reason: String::new(),
162	            interactive,
163	            rx_queue,
164	            seeding_source: true,
165	        }
166	    }
167	
168	    pub fn tick(&mut self) -> TickResult {
169	        self.tick_with_budget(DEFAULT_BATCH)
170	    }
171	
172	    pub fn tick_with_budget(&mut self, budget: u64) -> TickResult {
173	        if self.done {
174	            return TickResult { done: true };
175	        }
176	
177	        let mut total: u64 = 0;
178	        while total < budget {
179	            // Feed bytes opportunistically: every time the UART RX
180	            // register is empty, push the next queued byte. This
181	            // collapses what used to be N ticks of single-byte feed
182	            // into one tick that delivers bytes as fast as the
183	            // interpreter consumes them.
184	            while !self.rx_ready()
185	                && let Some(b) = self.rx_queue.pop_front()
186	            {
187	                self.emu.send_uart_byte(b);
188	                if self.rx_queue.is_empty() {
189	                    self.seeding_source = false;
190	                }
191	            }
192	
193	            let chunk = INNER_BATCH.min(budget - total);
194	            let result = self.emu.run_batch(chunk);
195	            self.instructions += result.instructions_run;
196	            total += result.instructions_run;
197	
198	            match result.reason {
199	                StopReason::Halted => {
200	                    self.done = true;
201	                    self.halted = true;
202	                    self.stop_reason = "halted".into();
203	                    break;
204	                }
205	                StopReason::InvalidInstruction(byte) => {
206	                    self.done = true;
207	                    self.stop_reason = format!(
208	                        "invalid instruction 0x{:02X} at PC=0x{:06X}",
209	                        byte,
210	                        self.emu.pc()
211	                    );
212	                    break;
213	                }
214	                StopReason::Breakpoint(addr) => {
215	                    self.done = true;
216	                    self.stop_reason = format!("breakpoint at 0x{:06X}", addr);
217	                    break;
