    // Sample PC at tick boundary. Inside the UART-RX
    // poll loop in getc, PC bounces among a handful
    // of addresses spanning only a few bytes; during
    // parsing/eval, PC scatters across the interp's
    // code. Require SAMPLES_REQUIRED consecutive tick
    // boundaries to land inside a PC_POLL_WINDOW-byte
    // window before trusting the interp is idle.
    const SAMPLES_REQUIRED: usize = 3;
    const PC_POLL_WINDOW: u32 = 64;
    let pc = session.pc();
