        self.pc_samples.remove(0);
    }
    let settled = self.pc_samples.len() == SAMPLES_REQUIRED && {
        let min = *self.pc_samples.iter().min().unwrap();
        let max = *self.pc_samples.iter().max().unwrap();
        max - min < PC_POLL_WINDOW
    };
